INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES
(gen_random_uuid(), 'ct', 7, 1, NULL, 'Bernardo de Claraval em Ct 7:1', 'Bernardo de Claraval destaca a síntese entre fé, razão e vida santa. Em Cânticos 7, o foco recai sobre adoração, sabedoria e temor do Senhor e chama a igreja para perseverança na tribulação. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'Bernardo de Claraval', 'commentary', '#6B4F2A', NOW()),
(gen_random_uuid(), 'ct', 8, 1, NULL, 'William Gurnall em Ct 8:1', 'William Gurnall interpreta este versículo a partir de a piedade prática e a santificação do coração. Em Cânticos 8, Deus revela adoração, sabedoria e temor do Senhor de forma pastoral e transformadora, promovendo fidelidade na aliança. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'William Gurnall', 'commentary', '#2E8B57', NOW()),
(gen_random_uuid(), 'is', 1, 1, NULL, 'Jonathan Edwards em Is 1:1', 'Jonathan Edwards destaca a piedade prática e a santificação do coração. Em Isaías 1, o foco recai sobre juízo, esperança e promessa messiânica e chama a igreja para santidade prática. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'Jonathan Edwards', 'commentary', '#2E8B57', NOW()),
(gen_random_uuid(), 'is', 2, 1, NULL, 'Charles Hodge em Is 2:1', 'Charles Hodge interpreta este versículo a partir de a coerência doutrinária aplicada à vida cristã. Em Isaías 2, Deus revela juízo, esperança e promessa messiânica de forma pastoral e transformadora, promovendo justiça com misericórdia. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'Charles Hodge', 'commentary', '#1D4ED8', NOW()),
(gen_random_uuid(), 'is', 3, 1, NULL, 'Agostinho de Hipona em Is 3:1', 'Segundo Agostinho de Hipona, a leitura cristológica e eclesial da passagem ilumina o sentido deste texto. Isaías 3 mostra que juízo, esperança e promessa messiânica sustenta a caminhada da fé, especialmente em adoração reverente. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'Agostinho de Hipona', 'commentary', '#8B4513', NOW()),
(gen_random_uuid(), 'is', 4, 1, NULL, 'Theodore Beza em Is 4:1', 'Na leitura de Theodore Beza, vemos a centralidade das Escrituras e da graça soberana. Isaías 4 evidencia juízo, esperança e promessa messiânica como eixo da vida do povo de Deus, com ênfase em amor fraternal. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'Theodore Beza', 'commentary', '#800080', NOW()),
(gen_random_uuid(), 'is', 5, 1, NULL, 'R. A. Torrey em Is 5:1', 'Segundo R. A. Torrey, o chamado ao arrependimento, fé viva e missão ilumina o sentido deste texto. Isaías 5 mostra que juízo, esperança e promessa messiânica sustenta a caminhada da fé, especialmente em arrependimento sincero. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'R. A. Torrey', 'commentary', '#0E7490', NOW()),
(gen_random_uuid(), 'is', 6, 1, NULL, 'Octavius Winslow em Is 6:1', 'Na leitura de Octavius Winslow, vemos a exposição textual com aplicação pastoral objetiva. Isaías 6 evidencia juízo, esperança e promessa messiânica como eixo da vida do povo de Deus, com ênfase em esperança escatológica. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'Octavius Winslow', 'commentary', '#B45309', NOW()),
(gen_random_uuid(), 'is', 7, 1, NULL, 'Heinrich Bullinger em Is 7:1', 'Heinrich Bullinger interpreta este versículo a partir de a centralidade das Escrituras e da graça soberana. Em Isaías 7, Deus revela juízo, esperança e promessa messiânica de forma pastoral e transformadora, promovendo santidade prática. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'Heinrich Bullinger', 'commentary', '#800080', NOW()),
(gen_random_uuid(), 'is', 8, 1, NULL, 'Dwight L. Moody em Is 8:1', 'Dwight L. Moody destaca o chamado ao arrependimento, fé viva e missão. Em Isaías 8, o foco recai sobre juízo, esperança e promessa messiânica e chama a igreja para justiça com misericórdia. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'Dwight L. Moody', 'commentary', '#0E7490', NOW()),
